/**
 * Tests for SubtitlesEditor pure utility functions
 * Covers: formatTimeDisplay, parseTimeInput, cuesToSRT, cuesToVTT,
 *         formatSRTTimestamp, formatVTTTimestamp, parseSRTContent,
 *         parseSRTTimestamp, validateCue, cueDuration, findActiveCue,
 *         sortCuesByTime, totalWordCount, estimateWPM
 */
import {
  formatTimeDisplay,
  parseTimeInput,
  cuesToSRT,
  cuesToVTT,
  formatSRTTimestamp,
  formatVTTTimestamp,
  parseSRTContent,
  parseSRTTimestamp,
  validateCue,
  cueDuration,
  findActiveCue,
  sortCuesByTime,
  totalWordCount,
  estimateWPM,
  SubtitleCue,
} from '@/components/editor/SubtitlesEditor';

// =============================================================================
// formatTimeDisplay
// =============================================================================

describe('formatTimeDisplay', () => {
  it('formats 0ms as 00:00.000', () => {
    expect(formatTimeDisplay(0)).toBe('00:00.000');
  });

  it('formats 1500ms as 00:01.500', () => {
    expect(formatTimeDisplay(1500)).toBe('00:01.500');
  });

  it('formats 65000ms as 01:05.000', () => {
    expect(formatTimeDisplay(65000)).toBe('01:05.000');
  });

  it('formats 3661234ms correctly', () => {
    // 3661234 ms = 61 min 1.234s = 61:01.234
    expect(formatTimeDisplay(3661234)).toBe('61:01.234');
  });

  it('clamps negative values to 00:00.000', () => {
    expect(formatTimeDisplay(-1000)).toBe('00:00.000');
  });
});

// =============================================================================
// parseTimeInput
// =============================================================================

describe('parseTimeInput', () => {
  it('parses MM:SS.mmm format', () => {
    expect(parseTimeInput('01:30.500')).toBe(90500);
  });

  it('parses MM:SS format', () => {
    expect(parseTimeInput('02:15')).toBe(135000);
  });

  it('parses SS.mmm format', () => {
    expect(parseTimeInput('45.250')).toBe(45250);
  });

  it('parses SS format (plain seconds)', () => {
    expect(parseTimeInput('10')).toBe(10000);
  });

  it('pads milliseconds if less than 3 digits', () => {
    expect(parseTimeInput('01:00.5')).toBe(60500);
    expect(parseTimeInput('01:00.50')).toBe(60500);
  });

  it('returns null for invalid format', () => {
    expect(parseTimeInput('abc')).toBeNull();
    expect(parseTimeInput('')).toBeNull();
    expect(parseTimeInput(':::')).toBeNull();
  });

  it('returns null if seconds >= 60 in MM:SS format', () => {
    expect(parseTimeInput('01:60')).toBeNull();
  });

  it('handles 0 values', () => {
    expect(parseTimeInput('0')).toBe(0);
    expect(parseTimeInput('00:00')).toBe(0);
    expect(parseTimeInput('00:00.000')).toBe(0);
  });
});

// =============================================================================
// formatSRTTimestamp / formatVTTTimestamp
// =============================================================================

describe('formatSRTTimestamp', () => {
  it('formats 0ms as 00:00:00,000', () => {
    expect(formatSRTTimestamp(0)).toBe('00:00:00,000');
  });

  it('formats 3723456ms correctly', () => {
    // 3723456ms = 1h 2m 3s 456ms
    expect(formatSRTTimestamp(3723456)).toBe('01:02:03,456');
  });

  it('formats sub-second timestamps', () => {
    expect(formatSRTTimestamp(500)).toBe('00:00:00,500');
  });

  it('handles negative as 00:00:00,000', () => {
    expect(formatSRTTimestamp(-100)).toBe('00:00:00,000');
  });
});

describe('formatVTTTimestamp', () => {
  it('formats same as SRT but with dot instead of comma', () => {
    expect(formatVTTTimestamp(3723456)).toBe('01:02:03.456');
  });

  it('formats 0ms as 00:00:00.000', () => {
    expect(formatVTTTimestamp(0)).toBe('00:00:00.000');
  });
});

// =============================================================================
// parseSRTTimestamp
// =============================================================================

describe('parseSRTTimestamp', () => {
  it('parses valid SRT timestamp', () => {
    expect(parseSRTTimestamp('01:02:03,456')).toBe(3723456);
  });

  it('parses 00:00:00,000 as 0', () => {
    expect(parseSRTTimestamp('00:00:00,000')).toBe(0);
  });

  it('returns 0 for invalid format', () => {
    expect(parseSRTTimestamp('invalid')).toBe(0);
  });

  it('roundtrips with formatSRTTimestamp', () => {
    const ms = 7531200;
    expect(parseSRTTimestamp(formatSRTTimestamp(ms))).toBe(ms);
  });
});

// =============================================================================
// cuesToSRT
// =============================================================================

describe('cuesToSRT', () => {
  const sampleCues: SubtitleCue[] = [
    { id: 1, startTime: 0, endTime: 3000, text: 'Hello world' },
    { id: 2, startTime: 3500, endTime: 7000, text: 'Second line' },
  ];

  it('generates valid SRT content', () => {
    const srt = cuesToSRT(sampleCues);
    expect(srt).toContain('1\n00:00:00,000 --> 00:00:03,000\nHello world');
    expect(srt).toContain('2\n00:00:03,500 --> 00:00:07,000\nSecond line');
  });

  it('returns empty string for empty array', () => {
    expect(cuesToSRT([])).toBe('');
  });

  it('preserves multiline text', () => {
    const cues: SubtitleCue[] = [
      { id: 1, startTime: 0, endTime: 3000, text: 'Line one\nLine two' },
    ];
    const srt = cuesToSRT(cues);
    expect(srt).toContain('Line one\nLine two');
  });
});

// =============================================================================
// cuesToVTT
// =============================================================================

describe('cuesToVTT', () => {
  const sampleCues: SubtitleCue[] = [
    { id: 1, startTime: 0, endTime: 3000, text: 'Hello' },
  ];

  it('starts with WEBVTT header', () => {
    const vtt = cuesToVTT(sampleCues);
    expect(vtt.startsWith('WEBVTT')).toBe(true);
  });

  it('uses dot separator (not comma)', () => {
    const vtt = cuesToVTT(sampleCues);
    expect(vtt).toContain('00:00:00.000 --> 00:00:03.000');
  });

  it('returns WEBVTT header for empty array', () => {
    const vtt = cuesToVTT([]);
    expect(vtt).toBe('WEBVTT\n\n');
  });
});

// =============================================================================
// parseSRTContent
// =============================================================================

describe('parseSRTContent', () => {
  it('parses standard SRT content', () => {
    const srt = `1
00:00:00,000 --> 00:00:03,000
Hello world

2
00:00:03,500 --> 00:00:07,000
Second line`;

    const cues = parseSRTContent(srt);
    expect(cues).toHaveLength(2);
    expect(cues[0].id).toBe(1);
    expect(cues[0].startTime).toBe(0);
    expect(cues[0].endTime).toBe(3000);
    expect(cues[0].text).toBe('Hello world');
    expect(cues[1].id).toBe(2);
    expect(cues[1].startTime).toBe(3500);
    expect(cues[1].endTime).toBe(7000);
    expect(cues[1].text).toBe('Second line');
  });

  it('handles multiline cue text', () => {
    const srt = `1
00:00:00,000 --> 00:00:03,000
Line one
Line two`;

    const cues = parseSRTContent(srt);
    expect(cues).toHaveLength(1);
    expect(cues[0].text).toBe('Line one\nLine two');
  });

  it('returns empty array for empty string', () => {
    expect(parseSRTContent('')).toEqual([]);
  });

  it('skips invalid blocks', () => {
    const srt = `invalid block

1
00:00:00,000 --> 00:00:03,000
Valid cue`;

    const cues = parseSRTContent(srt);
    expect(cues).toHaveLength(1);
    expect(cues[0].text).toBe('Valid cue');
  });

  it('roundtrips with cuesToSRT', () => {
    const original: SubtitleCue[] = [
      { id: 1, startTime: 1000, endTime: 4000, text: 'Test roundtrip' },
      { id: 2, startTime: 5000, endTime: 8500, text: 'Second cue' },
    ];
    const srt = cuesToSRT(original);
    const parsed = parseSRTContent(srt);
    expect(parsed).toHaveLength(2);
    expect(parsed[0].startTime).toBe(1000);
    expect(parsed[0].endTime).toBe(4000);
    expect(parsed[0].text).toBe('Test roundtrip');
    expect(parsed[1].startTime).toBe(5000);
    expect(parsed[1].endTime).toBe(8500);
  });
});

// =============================================================================
// validateCue
// =============================================================================

describe('validateCue', () => {
  it('returns empty array for valid cue', () => {
    const cue: SubtitleCue = { id: 1, startTime: 0, endTime: 3000, text: 'Hello' };
    expect(validateCue(cue)).toEqual([]);
  });

  it('detects negative start time', () => {
    const cue: SubtitleCue = { id: 1, startTime: -100, endTime: 3000, text: 'Hello' };
    const errors = validateCue(cue);
    expect(errors).toContain('Tempo inicial negativo');
  });

  it('detects end time <= start time', () => {
    const cue: SubtitleCue = { id: 1, startTime: 5000, endTime: 3000, text: 'Hello' };
    const errors = validateCue(cue);
    expect(errors).toContain('Tempo final deve ser maior que o inicial');
  });

  it('detects equal start and end time', () => {
    const cue: SubtitleCue = { id: 1, startTime: 3000, endTime: 3000, text: 'Hello' };
    const errors = validateCue(cue);
    expect(errors).toContain('Tempo final deve ser maior que o inicial');
  });

  it('detects empty text', () => {
    const cue: SubtitleCue = { id: 1, startTime: 0, endTime: 3000, text: '' };
    const errors = validateCue(cue);
    expect(errors).toContain('Texto vazio');
  });

  it('detects whitespace-only text as empty', () => {
    const cue: SubtitleCue = { id: 1, startTime: 0, endTime: 3000, text: '   ' };
    const errors = validateCue(cue);
    expect(errors).toContain('Texto vazio');
  });

  it('returns multiple errors', () => {
    const cue: SubtitleCue = { id: 1, startTime: -1, endTime: -1, text: '' };
    const errors = validateCue(cue);
    expect(errors.length).toBeGreaterThanOrEqual(2);
  });
});

