describe('cueDuration', () => {
  it('computes correct duration', () => {
    const cue: SubtitleCue = { id: 1, startTime: 1000, endTime: 4500, text: 'Test' };
    expect(cueDuration(cue)).toBe(3500);
  });

  it('returns 0 for zero-length cue', () => {
    const cue: SubtitleCue = { id: 1, startTime: 3000, endTime: 3000, text: 'Test' };
    expect(cueDuration(cue)).toBe(0);
  });

  it('returns 0 for inverted cue', () => {
    const cue: SubtitleCue = { id: 1, startTime: 5000, endTime: 3000, text: 'Test' };
    expect(cueDuration(cue)).toBe(0);
  });
});

// =============================================================================
// findActiveCue
// =============================================================================

describe('findActiveCue', () => {
  const cues: SubtitleCue[] = [
    { id: 1, startTime: 0, endTime: 3000, text: 'First' },
    { id: 2, startTime: 3500, endTime: 7000, text: 'Second' },
    { id: 3, startTime: 8000, endTime: 11000, text: 'Third' },
  ];

  it('finds cue at exact start time', () => {
    const active = findActiveCue(cues, 0);
    expect(active?.id).toBe(1);
  });

  it('finds cue within range', () => {
    const active = findActiveCue(cues, 5000);
    expect(active?.id).toBe(2);
  });

  it('returns null before end time (exclusive)', () => {
    const active = findActiveCue(cues, 3000);
    expect(active).toBeNull();
  });

  it('returns null in gap between cues', () => {
    const active = findActiveCue(cues, 3200);
    expect(active).toBeNull();
  });

  it('returns null after all cues', () => {
    const active = findActiveCue(cues, 99999);
    expect(active).toBeNull();
  });

  it('returns null for empty array', () => {
    expect(findActiveCue([], 1000)).toBeNull();
  });
});

// =============================================================================
// sortCuesByTime
// =============================================================================

describe('sortCuesByTime', () => {
  it('sorts by start time', () => {
    const cues: SubtitleCue[] = [
      { id: 1, startTime: 5000, endTime: 8000, text: 'B' },
      { id: 2, startTime: 0, endTime: 3000, text: 'A' },
      { id: 3, startTime: 10000, endTime: 13000, text: 'C' },
    ];
    const sorted = sortCuesByTime(cues);
    expect(sorted[0].text).toBe('A');
    expect(sorted[1].text).toBe('B');
    expect(sorted[2].text).toBe('C');
  });

  it('renumbers IDs sequentially', () => {
    const cues: SubtitleCue[] = [
      { id: 5, startTime: 5000, endTime: 8000, text: 'B' },
      { id: 3, startTime: 0, endTime: 3000, text: 'A' },
    ];
    const sorted = sortCuesByTime(cues);
    expect(sorted[0].id).toBe(1);
    expect(sorted[1].id).toBe(2);
  });

  it('does not mutate original array', () => {
    const cues: SubtitleCue[] = [
      { id: 1, startTime: 5000, endTime: 8000, text: 'B' },
      { id: 2, startTime: 0, endTime: 3000, text: 'A' },
    ];
    const sorted = sortCuesByTime(cues);
    expect(cues[0].startTime).toBe(5000);
    expect(sorted[0].startTime).toBe(0);
  });

  it('handles empty array', () => {
    expect(sortCuesByTime([])).toEqual([]);
  });
});

// =============================================================================
// totalWordCount
// =============================================================================

describe('totalWordCount', () => {
  it('counts words across all cues', () => {
    const cues: SubtitleCue[] = [
      { id: 1, startTime: 0, endTime: 3000, text: 'Hello world' },
      { id: 2, startTime: 3000, endTime: 6000, text: 'Three more words' },
    ];
    expect(totalWordCount(cues)).toBe(5);
  });

  it('returns 0 for empty array', () => {
    expect(totalWordCount([])).toBe(0);
  });

  it('handles multiline text', () => {
    const cues: SubtitleCue[] = [
      { id: 1, startTime: 0, endTime: 3000, text: 'Line one\nLine two' },
    ];
    expect(totalWordCount(cues)).toBe(4);
  });

  it('ignores extra whitespace', () => {
    const cues: SubtitleCue[] = [
      { id: 1, startTime: 0, endTime: 3000, text: '  spaced   out  ' },
    ];
    expect(totalWordCount(cues)).toBe(2);
  });
});

// =============================================================================
// estimateWPM
// =============================================================================

describe('estimateWPM', () => {
  it('calculates words per minute', () => {
    // 10 words in 30 seconds = 20 wpm
    const cues: SubtitleCue[] = [
      { id: 1, startTime: 0, endTime: 15000, text: 'one two three four five' },
      { id: 2, startTime: 15000, endTime: 30000, text: 'six seven eight nine ten' },
    ];
    expect(estimateWPM(cues)).toBe(20);
  });

  it('returns 0 for empty array', () => {
    expect(estimateWPM([])).toBe(0);
  });

  it('returns 0 for zero-duration cues', () => {
    const cues: SubtitleCue[] = [
      { id: 1, startTime: 5000, endTime: 5000, text: 'Hello' },
    ];
    expect(estimateWPM(cues)).toBe(0);
  });
});
